{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT MIN(CreatedDate), MAX(CreatedDate), MIN(CloseDate), MAX(CloseDate) FROM Opportunity;\"",
  "description": "Check opportunity date range"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT MIN(CompanySignedDate), MAX(CompanySignedDate) FROM Contract;\"",
  "description": "Check contract date range"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT o.OwnerId, COUNT(*) as cnt, AVG(DATE_DIFF('day', CAST(o.CreatedDate AS TIMESTAMP), CAST(c.CompanySignedDate AS TIMESTAMP))) as avg_days FROM Opportunity o JOIN Contract c ON o.ContractID__c = c.Id WHERE c.CompanySignedDate >= '2023-04-01' AND c.CompanySignedDate < '2023-05-01' GROUP BY o.OwnerId ORDER BY avg_days ASC LIMIT 10;\"",
  "description": "Check avg turnaround - by contract signed April 2023"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT o.OwnerId, COUNT(*) as cnt, AVG(DATE_DIFF('day', CAST(o.CreatedDate AS TIMESTAMP), CAST(c.CompanySignedDate AS TIMESTAMP))) as avg_days FROM Opportunity o JOIN Contract c ON o.ContractID__c = c.Id WHERE o.CreatedDate >= '2023-04-01' AND o.CreatedDate < '2023-05-01' GROUP BY o.OwnerId ORDER BY avg_days ASC LIMIT 10;\"",
  "description": "Check avg turnaround - by opp created April 2023"
}

{
  "command": "duckdb '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT o.OwnerId, COUNT(*) as cnt, AVG(DATE_DIFF('day', CAST(o.CreatedDate AS TIMESTAMP), CAST(c.CompanySignedDate AS TIMESTAMP))) as avg_days FROM Opportunity o JOIN Contract c ON o.ContractID__c = c.Id WHERE o.CloseDate >= '2023-04-01' AND o.CloseDate < '2023-05-01' GROUP BY o.OwnerId ORDER BY avg_days ASC LIMIT 10;\"",
  "description": "Check avg turnaround - by opp closed April 2023"
}
